(258, 259, 'COM_FWREALESTATE', 'component', 'com_fwrealestate', '', '', 1, 1, 0, 0, 0, '{\"name\":\"COM_FWREALESTATE\",\"type\":\"component\",\"creationDate\":\"2025-10-17\",\"author\":\"Fastw3b - Effective Web Solutions\",\"copyright\":\"(C) 2025 Fastw3b LLC. All rights reserved.\",\"authorEmail\":\"dev@fastw3b.net\",\"authorUrl\":\"https:\\/\\/www.fastw3b.net\",\"version\":\"6.1.0\",\"description\":\"COM_FWREALESTATE_TEXT\",\"group\":\"\",\"changelogurl\":\"\",\"filename\":\"fwrealestate\"}', '{\"update_notes\":false,\"langs_data\":{},\"extensions_data\":\"[{\\\"id\\\":2,\\\"parent\\\":0,\\\"type\\\":\\\"product\\\",\\\"name\\\":\\\"FW Real Estate\\\",\\\"update_name\\\":\\\"com_fwrealestate\\\",\\\"image\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/uploads\\\\\\/products\\\\\\/4e83099d75742b0601d91cdd1598bffe.png\\\",\\\"is_free\\\":1,\\\"price\\\":0,\\\"version_price\\\":0,\\\"days\\\":0,\\\"short\\\":\\\"Real estate listing platform for individual agents, brokers, and agencies. MLS integration included in Professional and Agency tiers, plus a full addon library covering search, property management, agents, SEO, and custom fields. Self-hosted on Joomla or WordPress, one subscription covers everything.\\\",\\\"doc_link\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/documentation\\\\\\/joomla\\\\\\/fw-real-estate\\\",\\\"frontend_demo_link\\\":\\\"https:\\\\\\/\\\\\\/demo.fastw3b.com\\\\\\/realestate\\\\\\/\\\",\\\"published\\\":1,\\\"_addon_type\\\":\\\"Component\\\",\\\"_comp_version\\\":null,\\\"_version\\\":\\\"6.1.2\\\",\\\"_version_date\\\":\\\"2026-03-30 10:55:43\\\",\\\"_required\\\":[],\\\"_related\\\":[],\\\"_ordering\\\":63,\\\"_badges\\\":[],\\\"_installable\\\":1,\\\"author\\\":\\\"Fastw3b\\\",\\\"link\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/products\\\\\\/fw-real-estate\\\"},{\\\"id\\\":167,\\\"parent\\\":0,\\\"type\\\":\\\"service\\\",\\\"name\\\":\\\"Theme Integration\\\",\\\"update_name\\\":\\\"Theme Integration\\\",\\\"image\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/uploads\\\\\\/products\\\\\\/40062dba3b786d4ca11af15721ee1320.webp\\\",\\\"is_free\\\":0,\\\"price\\\":0,\\\"version_price\\\":0,\\\"days\\\":0,\\\"short\\\":\\\"Your product pages should look like they belong on your website, not like a third-party add-on. We match colors, fonts, layout, and spacing so everything blends with your theme.\\\",\\\"doc_link\\\":\\\"\\\",\\\"frontend_demo_link\\\":\\\"\\\",\\\"published\\\":1,\\\"_addon_type\\\":\\\"service\\\",\\\"_comp_version\\\":null,\\\"_version\\\":null,\\\"_version_date\\\":null,\\\"_required\\\":[],\\\"_related\\\":[],\\\"_ordering\\\":0,\\\"_badges\\\":[],\\\"_installable\\\":null,\\\"author\\\":\\\"Fastw3b\\\",\\\"link\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/services\\\\\\/theme-integration\\\"},{\\\"id\\\":168,\\\"parent\\\":0,\\\"type\\\":\\\"service\\\",\\\"name\\\":\\\"Website Speed Boost\\\",\\\"update_name\\\":\\\"Website Speed Boost\\\",\\\"image\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/uploads\\\\\\/products\\\\\\/8997082f208cfcd04af4b67efdde23bb.webp\\\",\\\"is_free\\\":0,\\\"price\\\":0,\\\"version_price\\\":0,\\\"days\\\":0,\\\"short\\\":\\\"Your website is slow and losing visitors? We audit every bottleneck, optimize images, caching, and database, and deliver a before\\\\\\/after speed report with measurable results.\\\",\\\"doc_link\\\":\\\"\\\",\\\"frontend_demo_link\\\":\\\"\\\",\\\"published\\\":1,\\\"_addon_type\\\":\\\"service\\\",\\\"_comp_version\\\":null,\\\"_version\\\":null,\\\"_version_date\\\":null,\\\"_required\\\":[],\\\"_related\\\":[],\\\"_ordering\\\":0,\\\"_badges\\\":[],\\\"_installable\\\":null,\\\"author\\\":\\\"Fastw3b\\\",\\\"link\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/services\\\\\\/website-speed-boost\\\"},{\\\"id\\\":125,\\\"parent\\\":0,\\\"type\\\":\\\"service\\\",\\\"name\\\":\\\"Custom Feature Development\\\",\\\"update_name\\\":\\\"Custom Feature Development\\\",\\\"image\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/uploads\\\\\\/products\\\\\\/122d51c4d4dc24198bf1bbea9cb8f25a.webp\\\",\\\"is_free\\\":0,\\\"price\\\":0,\\\"version_price\\\":0,\\\"days\\\":0,\\\"short\\\":\\\"Need a feature that does not exist yet? We build it as a private addon for your CMS extension or as a module for your custom platform. Clean, documented, update-safe.\\\",\\\"doc_link\\\":\\\"\\\",\\\"frontend_demo_link\\\":\\\"\\\",\\\"published\\\":1,\\\"_addon_type\\\":\\\"service\\\",\\\"_comp_version\\\":null,\\\"_version\\\":null,\\\"_version_date\\\":null,\\\"_required\\\":[],\\\"_related\\\":[],\\\"_ordering\\\":2,\\\"_badges\\\":[],\\\"_installable\\\":null,\\\"author\\\":\\\"Fastw3b\\\",\\\"link\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/services\\\\\\/custom-feature-development\\\"},{\\\"id\\\":161,\\\"parent\\\":0,\\\"type\\\":\\\"service\\\",\\\"name\\\":\\\"Website Maintenance\\\",\\\"update_name\\\":\\\"Website Maintenance\\\",\\\"image\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/uploads\\\\\\/products\\\\\\/512cf63b93b440bf63008556b93a2371.webp\\\",\\\"is_free\\\":0,\\\"price\\\":0,\\\"version_price\\\":0,\\\"days\\\":0,\\\"short\\\":\\\"Annual website maintenance: monthly updates, security scans, backup verification, uptime monitoring, and emergency fix allowance. Your site stays secure and current.\\\",\\\"doc_link\\\":\\\"\\\",\\\"frontend_demo_link\\\":\\\"\\\",\\\"published\\\":1,\\\"_addon_type\\\":\\\"service\\\",\\\"_comp_version\\\":null,\\\"_version\\\":null,\\\"_version_date\\\":null,\\\"_required\\\":[],\\\"_related\\\":[],\\\"_ordering\\\":3,\\\"_badges\\\":[],\\\"_installable\\\":null,\\\"author\\\":\\\"Fastw3b\\\",\\\"link\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/services\\\\\\/website-maintenance\\\"},{\\\"id\\\":150,\\\"parent\\\":0,\\\"type\\\":\\\"service\\\",\\\"name\\\":\\\"Emergency Fix & Recovery\\\",\\\"update_name\\\":\\\"Emergency Fix & Recovery\\\",\\\"image\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/uploads\\\\\\/products\\\\\\/f5892166b3cf00652ed63a73aa8dd165.webp\\\",\\\"is_free\\\":0,\\\"price\\\":0,\\\"version_price\\\":0,\\\"days\\\":0,\\\"short\\\":\\\"Something on your website is broken? We diagnose and fix the issue, from minor display glitches to critical site failures. One issue per order.\\\",\\\"doc_link\\\":\\\"\\\",\\\"frontend_demo_link\\\":\\\"\\\",\\\"published\\\":1,\\\"_addon_type\\\":\\\"service\\\",\\\"_comp_version\\\":null,\\\"_version\\\":null,\\\"_version_date\\\":null,\\\"_required\\\":[],\\\"_related\\\":[],\\\"_ordering\\\":4,\\\"_badges\\\":[],\\\"_installable\\\":null,\\\"author\\\":\\\"Fastw3b\\\",\\\"link\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/services\\\\\\/emergency-fix-recovery\\\"},{\\\"id\\\":157,\\\"parent\\\":0,\\\"type\\\":\\\"service\\\",\\\"name\\\":\\\"Data Import & Migration\\\",\\\"update_name\\\":\\\"Data Import & Migration\\\",\\\"image\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/uploads\\\\\\/products\\\\\\/395b3ca7dac47702f5b8673e490c9bd0.webp\\\",\\\"is_free\\\":0,\\\"price\\\":0,\\\"version_price\\\":0,\\\"days\\\":0,\\\"short\\\":\\\"Have data in spreadsheets, another CMS, or an old system? We import it into your website cleanly. Every record mapped, verified, and ready to use.\\\",\\\"doc_link\\\":\\\"\\\",\\\"frontend_demo_link\\\":\\\"\\\",\\\"published\\\":1,\\\"_addon_type\\\":\\\"service\\\",\\\"_comp_version\\\":null,\\\"_version\\\":null,\\\"_version_date\\\":null,\\\"_required\\\":[],\\\"_related\\\":[],\\\"_ordering\\\":6,\\\"_badges\\\":[],\\\"_installable\\\":null,\\\"author\\\":\\\"Fastw3b\\\",\\\"link\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/services\\\\\\/data-import-migration\\\"},{\\\"id\\\":108,\\\"parent\\\":0,\\\"type\\\":\\\"service\\\",\\\"name\\\":\\\"Joomla & WordPress Plugin Setup\\\",\\\"update_name\\\":\\\"Joomla & WordPress Plugin Setup\\\",\\\"image\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/uploads\\\\\\/products\\\\\\/74d11e50e060f45ff2680f58dc23eccb.webp\\\",\\\"is_free\\\":0,\\\"price\\\":0,\\\"version_price\\\":0,\\\"days\\\":0,\\\"short\\\":\\\"Need a Joomla extension or WordPress plugin installed and configured on your website? We handle the install, the setup, and the verification. From a simple contact form to a full WooCommerce store.\\\",\\\"doc_link\\\":\\\"\\\",\\\"frontend_demo_link\\\":\\\"\\\",\\\"published\\\":1,\\\"_addon_type\\\":\\\"service\\\",\\\"_comp_version\\\":null,\\\"_version\\\":null,\\\"_version_date\\\":null,\\\"_required\\\":[],\\\"_related\\\":[],\\\"_ordering\\\":8,\\\"_badges\\\":[],\\\"_installable\\\":null,\\\"author\\\":\\\"Fastw3b\\\",\\\"link\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/services\\\\\\/joomla-wordpress-plugin-setup\\\"},{\\\"id\\\":23,\\\"parent\\\":0,\\\"type\\\":\\\"service\\\",\\\"name\\\":\\\"Real Estate Website Package\\\",\\\"update_name\\\":\\\"Real Estate Website Package\\\",\\\"image\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/uploads\\\\\\/products\\\\\\/d5fc9d2d9870d30aed0f4995c84ac4eb.webp\\\",\\\"is_free\\\":0,\\\"price\\\":0,\\\"version_price\\\":0,\\\"days\\\":0,\\\"short\\\":\\\"A complete real estate website delivered by a set date. Configuration, design, MLS integration, SEO, and training. You provide the domain, we handle everything else.\\\",\\\"doc_link\\\":\\\"\\\",\\\"frontend_demo_link\\\":\\\"\\\",\\\"published\\\":1,\\\"_addon_type\\\":\\\"service\\\",\\\"_comp_version\\\":null,\\\"_version\\\":null,\\\"_version_date\\\":null,\\\"_required\\\":[],\\\"_related\\\":[],\\\"_ordering\\\":9,\\\"_badges\\\":[],\\\"_installable\\\":null,\\\"author\\\":\\\"Fastw3b\\\",\\\"link\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/services\\\\\\/fwre-website-package\\\"},{\\\"id\\\":154,\\\"parent\\\":0,\\\"type\\\":\\\"service\\\",\\\"name\\\":\\\"Custom MLS Integration\\\",\\\"update_name\\\":\\\"Custom MLS Integration\\\",\\\"image\\\":\\\"https:\\\\\\/\\\\\\/fastw3b.com\\\\\\/uploads\\\\\\/products\\\\\\/b54a1aa142064b36cec84bcb294d7ee3.webp\\\",\\\"is_free\\\":0,\\\"price\\\":0,\\\"version_price\\\":0,\\\"