INSERT INTO `duew9_jea_properties` (`id`, `asset_id`, `ref`, `title`, `alias`, `transaction_type`, `type_id`, `price`, `rate_frequency`, `address`, `town_id`, `area_id`, `zip_code`, `department_id`, `condition_id`, `living_space`, `land_space`, `rooms`, `bedrooms`, `charges`, `fees`, `deposit`, `hot_water_type`, `heating_type`, `bathrooms`, `toilets`, `availability`, `floor`, `floors_number`, `orientation`, `amenities`, `description`, `slogan_id`, `published`, `access`, `ordering`, `featured`, `created`, `modified`, `publish_up`, `publish_down`, `checked_out`, `checked_out_time`, `created_by`, `hits`, `images`, `latitude`, `longitude`, `notes`, `language`, `provider`) VALUES
(2, 118, '2', 'Оренда 2-кімнатної квартири в житловому стані', 'orenda-2-kimnatnoi-kvartyry-v-zhytlovomu-stani', 'RENTING', 1, 10000.00, 'MONTHLY', 'Вишиванки', 1, 1, '33000', 2, 4, 55, 60, 2, 2, 2000.00, 0.00, 0.00, 3, 1, 0, 1, '0000-00-00', 6, 10, '0', '-3-', 'Здається простора квартира з роздільними кімнатами за вигідною ціною.\r\nСтан житловий, є всі необхідні меблі для комфортного проживання.\r\nРозташування: тихий район з розвиненою інфраструктурою, поруч парк та супермаркети.\r\nГаряча вода подається через бойлер, що забезпечує незалежність від міських мереж.\r\nГотова до заселення вже сьогодні.\r\n\r\n', 5, 1, 1, 2, 0, '2026-01-01 13:01:49', '2026-01-01 14:08:47', '2025-12-25 15:32:46', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 185, '[{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Studentska_1.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Studentska_2.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Studentska_3.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Strutinska_4.jpg\"}]', '', '', '', '*', ''),
(3, 119, '3', 'Елітні апартаменти в новобудові з охороною', 'elitni-apartamenty-v-novobudovi-z-okhoronoiu', 'RENTING', 1, 30000.00, 'MONTHLY', 'Студентська', 1, 1, '33000', 2, 4, 65, 70, 2, 2, 7000.00, 0.00, 0.00, 3, 1, 0, 1, '0000-00-00', 4, 5, '0', '-4-', 'Дизайнерський ремонт з використанням якісних матеріалів.\r\nКухня-студія та окрема спальня зі Smart TV.\r\nВ будинку є власна котельня та відеоспостереження на поверсі.\r\nДодатково оплачуються лише комунальні послуги за лічильниками.\r\nЄ закріплене паркомісце в підземному паркінгу.\r\n\r\n', 5, 1, 1, 3, 0, '2026-01-01 13:06:17', '2026-01-01 14:08:38', '2025-12-25 15:32:46', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 186, '[{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Bukov_45_2.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Bukov_45_1.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Bukov_45_3.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Bukov_45_4.jpg\"}]', '', '', '', '*', ''),
(4, 120, '1', 'Оренда 2-кімнатної квартири в житловому стані', 'orenda-2-kimnatnoi-kvartyry-v-zhytlovomu-stani-2', 'RENTING', 1, 10000.00, 'MONTHLY', 'Вишиванки', 1, 1, '33000', 2, 4, 55, 60, 2, 2, 2000.00, 0.00, 0.00, 3, 1, 0, 1, '0000-00-00', 6, 10, '0', '-3-', 'Здається простора квартира з роздільними кімнатами за вигідною ціною.\r\nСтан житловий, є всі необхідні меблі для комфортного проживання.\r\nРозташування: тихий район з розвиненою інфраструктурою, поруч парк та супермаркети.\r\nГаряча вода подається через бойлер, що забезпечує незалежність від міських мереж.\r\nГотова до заселення вже сьогодні.\r\n\r\n', 5, 1, 1, 4, 0, '2026-01-01 13:12:52', '2026-01-01 14:08:12', '2025-12-25 15:32:46', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 185, '[{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Strutinska_1.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Strutinska_2.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Strutinska_3.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Strutinska_4.jpg\"}]', '', '', '', '*', ''),
(5, 121, '4', 'Оренда затишної 1-кімнатної квартири з сучасним ремонтом', 'orenda-zatyshnoi-1-kimnatnoi-kvartyry-z-suchasnym-remontom', 'RENTING', 1, 8000.00, 'MONTHLY', 'Степана Бандери', 1, 1, '33000', 2, 4, 30, 35, 1, 1, 1000.00, 0.00, 0.00, 3, 1, 0, 1, '0000-00-00', 2, 10, '0', '-3-', 'Здається світла та компактна квартира, ідеальна для однієї людини або молодої пари.\r\nУ квартирі виконано якісний косметичний ремонт, встановлено сучасні металопластикові вікна.\r\nКомфорт: Повністю мебльована (диван-ліжко, шафа-купе), є необхідна техніка: холодильник, пральна машина та мікрохвильова піч.\r\nГаряча вода: Встановлено бойлер, що гарантує наявність гарячої води цілий рік.\r\nІнфраструктура: Будинок розташований поруч із зупинкою транспорту, аптеками та продуктовими магазинами.\r\n\r\n\r\n', 5, 1, 1, 5, 0, '2026-01-01 13:16:41', '2026-01-01 14:08:04', '2025-12-25 15:32:46', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 188, '[{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Grush1.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Strutinska_3.jpg\"}]', '', '', '', '*', ''),
(6, 122, '5', 'Оренда просторої 3-кімнатної квартири для великої родини', 'orenda-zatyshnoi-1-kimnatnoi-kvartyry-z-suchasnym-remontom-2', 'RENTING', 1, 15000.00, 'MONTHLY', 'Ювілейна', 1, 1, '33000', 2, 4, 70, 75, 1, 1, 1000.00, 0.00, 0.00, 3, 1, 0, 1, '0000-00-00', 2, 10, '0', '-1-', 'Пропонується в оренду велика квартира з функціональним плануванням та роздільними кімнатами.\r\nСтан: Квартира у відмінному житловому стані, чиста, тепла та затишна.\r\nМеблювання: Наявні спальні місця у кожній кімнаті, облаштована робоча зона та місткі системи зберігання речей.\r\nТехнічне оснащення: Опалення централізоване, для підігріву води встановлено ємнісний бойлер.\r\nПереваги: Тихий двір з дитячим майданчиком, поруч школа та дитячий садок. Гарна транспортна розв\'язка.\r\n\r\n\r\n\r\n', 5, 1, 1, 6, 0, '2026-01-01 13:23:25', '2026-01-01 14:07:46', '2025-12-25 15:32:46', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 192, '[{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_3_kimn.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_3_kimn_1.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_3_kimn_2.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_3_kimn_3.jpg\"}]', '', '', '', '*', ''),
(7, 123, '6', 'Оренда окремого будинку з власною територією та гаражем', 'orenda-okremoho-budynku-z-vlasnoiu-terytoriieiu-ta-harazhem', 'RENTING', 2, 12000.00, 'MONTHLY', 'Соборна', 1, 1, '33000', 2, 4, 70, 78, 2, 2, 3000.00, 0.00, 0.00, 3, 1, 0, 1, '0000-00-00', 1, 1, '0', '-1-', 'Здається в оренду комфортабельний будинок для довгострокового проживання.\r\nПланування: Будинок має простору вітальню, декілька спалень та велику кухню-їдальню.\r\nТериторія: Власне огороджене подвір\'я, зона для відпочинку (барбекю) та місце для паркування автомобіля (гараж).\r\nСтан та меблі: Виконано якісний ремонт, будинок повністю укомплектований сучасними меблями та побутовою технікою для вашого комфорту.\r\nКомунікації: Автономне опалення, що дозволяє самостійно регулювати температуру, та бойлер для постійного постачання гарячої води.\r\nРозташування: Спокійний район, зручний доїзд до центру міста, поруч магазини та зупинка громадського транспорту.\r\n', 5, 1, 1, 7, 0, '2026-01-01 13:41:30', '2026-01-01 14:09:50', '2025-12-25 15:32:46', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 188, '[{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_budinku_Soborna.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_budinku_Soborna1.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_budinku_Soborna2.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_budinku_Soborna3.jpg\"}]', '', '', '', '*', ''),
(8, 124, '7', 'Продаж просторої 2-кімнатної квартири', 'prodazh-prostoroi-2-kimnatnoi-kvartyry', 'SELLING', 1, 1360000.00, 'MONTHLY', 'Відінська, 30', 1, 1, '33000', 1, 4, 60, 62, 2, 2, 0.00, 0.00, 0.00, 3, 1, 0, 1, '0000-00-00', 2, 10, '0', '-1-', 'Терміново! Продається 2х кімнатна квартира від власника по вул Відінська 36, 3 поверх з 5ти. Площа 44 м², продається з УСІМА МЕБЛЯМИ та побутовою технікою. Вселяйся та живи. Торг присутній.\r\n\r\n\r\n\r\n', 5, 1, 1, 8, 0, '2026-01-01 13:51:08', '2026-01-01 14:25:22', '2025-12-25 15:32:46', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 188, '[{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Bukov_45_3.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Bukov_45_1.jpg\"}]', '', '', '', '*', ''),
(9, 125, '8', 'Продаж затишної 1-кімнатної квартири з сучасним плануванням', 'prodazh-zatyshnoi-1-kimnatnoi-kvartyry-z-suchasnym-planuvanniam', 'SELLING', 1, 1250000.00, 'MONTHLY', 'Соборна 366', 1, 1, '33000', 1, 4, 40, 42, 1, 0, 0.00, 0.00, 0.00, 3, 1, 0, 1, '0000-00-00', 3, 10, '0', '-2-', 'Пропонується до продажу світла квартира в новому житловому комплексі міста Рівне.\r\nЗагальна площа: 42 м², кухня з панорамними вікнами, що додає простору та світла.\r\nСтан: Після будівельників, зроблена чистова стяжка та розводка електрики — ідеальний варіант під індивідуальний дизайн.\r\nПереваги: Автономне опалення (двоконтурний котел), встановлені лічильники та якісні вхідні двері.\r\nДокументи готові до швидкої переоформлення, можливий невеликий торг.\r\n\r\n\r\n\r\n', 5, 1, 1, 9, 0, '2026-01-01 14:22:04', '2026-01-01 14:26:45', '2025-12-25 15:32:46', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 189, '[{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Bukov_45_3.jpg\"},{\"title\":\"\",\"description\":\"\",\"name\":\"Orenda_Strutinska_2.jpg\"},{\"name\":\"Orenda_Bukov_45_1.jpg\",\"title\":\"\",\"description\":\"\"}]', '', '', '', '*', ''),
(10, 126, '9', 'Продаж просторої 3-кімнатної квартири для великої родини', 'prodazh-prostoroi-3-kimnatnoi-kvartyry-dlia-velykoi-rodyny', 'SELLING', 1, 2480000.00, 'MONTHLY', 'Відінська 36', 1, 1, '33000', 1, 4, 72, 75, 3, 3, 0.00, 0.00, 0.00, 3, 1, 3, 1, '0000-00-00', 3, 10, '0', '-2-', 'Продається велика трикімнатна квартира з роздільними кімнатами та двома заскленими лоджіями.\r\nПлоща: 75 м², зручний середній поверх, квартира не кутова, дуже тепла.\r\nРемонт: Виконано капітальний ремонт у 2023 році: замінені труби, сантехніка та встановлено нові радіатори.\r\nКомплектація: Вбудована кухня з технікою, в передпокої — велика гардеробна.\r\nІнфраструктура: Поруч школа, садочок, парк для прогулянок та мережа супермаркетів.\r\nЦіна: 2 480 000 грн.\r\n\r\n\r\n\r\n', 5, 1, 1, 10, 0, '2026-01-01 14:27:36', '2026-01-01 14:49:12', '2025-12-25 15:32:46', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 192, '[{\"name\":\"Orenda_Strutinska_4.jpg\",\"title\":\"\",\"description\":\"\"},{\"name\":\"Orenda_Studentska_1.jpg\",\"title\":\"\",\"description\":\"\"},{\"name\":\"Orenda_Strutinska_3.jpg\",\"title\":\"\",\"description\":\"\"}]', '', '', '', '*', ''),
(12, 128, '10', 'Продаж сучасного будинку з ділянкою та всіма зручностями', 'prodazh-suchasnoho-budynku-z-diliankoiu-ta-vsima-zruchnostiamy', 'SELLING', 2, 3800000.00, 'MONTHLY', 'С. Бармаки, Рівненська', 1, 1, '33000', 1, 4, 72, 75, 3, 3, 0.00, 0.00, 0.00, 3, 1, 3, 1, '0000-00-00', 0, 0, '0', '-1-', 'Пропонується до продажу окремий будинок у затишному передмісті Рівного.\r\nПлоща та планування: Загальна площа 120 м², будинок включає три спальні, простору кухню-студію з виходом на терасу та два санвузли.\r\nДілянка: Приватизована земельна ділянка площею 6 соток, огороджена парканом, є місце для паркування двох авто та зона для барбекю.\r\nТехнічні характеристики: Опалення забезпечується сучасним енергоефективним котлом, встановлено бойлер для гарячої води та систему очищення води.\r\nСтан: У будинку виконано якісний ремонт, встановлено панорамні енергозберігаючі вікна та броньовані двері.\r\nЦіна: 3 800 000 грн.\r\nБудинок введений в експлуатацію, повний пакет документів готовий до оформлення угоди купівлі-продажу.\r\n', 5, 1, 1, 11, 0, '2026-01-01 15:02:59', '2026-01-11 11:50:56', '2026-01-01 14:00:20', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 1, '[{\"title\":\"\",\"description\":\"\",\"name\":\"Prodag_Kotedg_Bud1.jpg\"}]', '', '', '', '*', ''),
(13, 129, '11', 'Оренда сучасного котеджу (р-н Щасливе)', 'orenda-suchasnoho-kotedzhu-r-n-shchaslyve', 'RENTING', 2, 20000.00, 'MONTHLY', 'В’ячеслава Чорновола', 1, 1, '33000', 2, 4, 110, 110, 3, 2, 3000.00, 0.00, 0.00, 3, 1, 1, 0, '0000-00-00', 2, 2, '0', '-4-', 'Загальна площа: 110 $m^2$.Планування: Двоповерховий будинок: на першому поверсі — простора кухня-вітальня та санвузол, на другому — три окремі спальні та ванна кімната.Стан: Дизайнерський ремонт, перша здача. Будинок повністю укомплектований новими меблями та побутовою технікою (посудомийна машина, духова шафа, плазмовий TV).Комунікації: Автономне газове опалення, встановлено систему \"тепла підлога\" по всьому першому поверху.Територія: Закрите подвір’я з ландшафтним дизайном, паркомісце на два автомобілі. Ціна: 20 000 грн/міс.', 5, 1, 1, 12, 0, '2026-01-11 11:18:42', '2026-01-11 11:30:06', '2026-01-11 10:13:26', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 5, '[{\"name\":\"Orenda-budin-Chaslive1.jpg\",\"title\":\"\",\"description\":\"\"},{\"name\":\"Orenda-budin-Chaslive.jpg\",\"title\":\"\",\"description\":\"\"},{\"name\":\"Orenda-budin-Chaslive2.jpg\",\"title\":\"\",\"description\":\"\"},{\"name\":\"Orenda-budin-Chaslive3.jpg\",\"title\":\"\",\"description\":\"\"}]', '', '', '', '*', ''),
(14, 130, '12', 'Оренда будинку в приватному секторі (р-н Пивзавод)', 'orenda-budynku-v-pryvatnomu-sektori-r-n-pyvzavod', 'RENTING', 2, 16500.00, 'MONTHLY', 'Соборна, 360', 1, 1, '33000', 2, 4, 85, 85, 3, 2, 2500.00, 0.00, 0.00, 3, 1, 1, 0, '0000-00-00', 1, 1, '0', '-1-', 'Загальна площа: 85 $m^2$.Деталі: Окремий будинок з капітальним ремонтом. Три житлові кімнати, велика кухня та веранда.Зручності: Є всі необхідні меблі (ліжка з ортопедичними матрацами, шафи), холодильник, пральна машина.Гаряча вода та тепло: Встановлено двоконтурний котел та додатковий бойлер на випадок профілактичних робіт.Переваги: Наявність цегляного гаража на території, фруктовий сад, тихе місце в межах міста.Ціна: 16 500 грн/міс.', 5, 1, 1, 13, 0, '2026-01-11 11:31:02', '2026-01-11 11:35:49', '2026-01-11 10:13:26', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 5, '[{\"name\":\"Orenda-budin-Pivzavod.jpg\",\"title\":\"\",\"description\":\"\"},{\"name\":\"Orenda-budin-Pivzavod1.jpg\",\"title\":\"\",\"description\":\"\"},{\"name\":\"Orenda-budin-Pivzavod2.jpg\",\"title\":\"\",\"description\":\"\"},{\"name\":\"Orenda-budin-Chaslive3.jpg\",\"title\":\"\",\"description\":\"\"}]', '', '', '', '*', ''),
(15, 131, '13', 'Елітний особняк у районі «Тинне»', 'elitnyi-osobniak-u-raioni-tynne', 'SELLING', 2, 42000000.00, 'MONTHLY', 'м. Рівне, вул. Тиннівська, 45.', 1, 1, '33000', 1, 4, 185, 185, 3, 3, 0.00, 0.00, 0.00, 3, 1, 1, 1, '0000-00-00', 2, 2, '0', '-3-', 'Загальна площа: 165 м², ділянка — 8 соток.\r\nПланування: На першому поверсі розташована кухня-студія з виходом на криту терасу, гостьова спальня та санвузол. На другому — три дитячі кімнати, майстер-спальня з гардеробом та велика ванна кімната.\r\nТехнічні деталі: Будинок побудований з червоної цегли, утеплений мінватою (100 мм). Встановлено панорамні енергозберігаючі вікна.\r\nКомунікації: Автономне газове опалення, власна свердловина, септик з переливом.\r\nЦіна: 4 200 000 грн.\r\nСтатус: Об\'єкт готовий до продажу, документи перевірені юристом.', 5, 1, 1, 14, 0, '2026-01-11 11:45:47', '2026-01-11 11:55:03', '2026-01-11 10:13:26', '0000-00-00 00:00:00', 0, '0000-00-00 00:00:00', 465, 5, '[{\"name\":\"Prodag-Budinok-Tinne.jpg\",\"title\":\"\",\"description\":\"\"},{\"name\":\"Prodag-Budinok-Tinne1.jpg\",\"title\":\"\",\"description\":\"\"},{\"name\":\"Prodag-Budinok-Tinne2.jpg\",\"title\":\"\",\"description\":\"\"},{\"name\":\"Prodag-Budinok-Tinne3.jpg\",\"title\":\"\",\"description\":\"\"}]', '', '', '', '*', '');
