(116, 114, 'Фільтри', '', '<div id=\"final-filter-box\" style=\"background:#f1f3f5; padding:20px; border-radius:12px; border:3px solid #28a745; margin: 20px 0; font-family: sans-serif;\">\r\n    <div style=\"display:flex; gap:10px; flex-wrap:wrap;\">\r\n\r\n        <div style=\"flex:1; min-width:200px;\">\r\n            <label style=\"font-weight:bold; display:block; margin-bottom:5px;\">Кількість кімнат:</label>\r\n            <select id=\"my-rooms\" style=\"width:100%; height:45px; font-size:16px;\">\r\n                <option value=\"\">Усі варіанти</option>\r\n                <option value=\"1-кімнатна\">1-кімнатні</option>\r\n                <option value=\"2-кімнатна\">2-кімнатні</option>\r\n                <option value=\"3-кімнатна\">3-кімнатні</option>\r\n            </select>\r\n        </div>\r\n\r\n        <div style=\"flex:1; min-width:150px;\">\r\n            <label style=\"font-weight:bold; display:block; margin-bottom:5px;\">Бюджет до:</label>\r\n            <input type=\"number\" id=\"my-price\" placeholder=\"Грн\" style=\"width:100%; height:45px; font-size:16px; padding-left:10px;\">\r\n        </div>\r\n\r\n        <div style=\"width:100%; display:flex; gap:10px; margin-top:10px;\">\r\n            <button type=\"button\" onclick=\"forceFilter()\" style=\"flex:3; background:#28a745; color:#fff; border:none; height:55px; border-radius:8px; font-size:18px; font-weight:bold; cursor:pointer;\">\r\n                ЗАСТОСУВАТИ\r\n            </button>\r\n            <button type=\"button\" onclick=\"forceReset()\" style=\"flex:1; background:#adb5bd; color:#fff; border:none; height:55px; border-radius:8px; cursor:pointer;\">\r\n                🔄\r\n            </button>\r\n        </div>\r\n    </div>\r\n</div>\r\n\r\n<script>\r\nfunction forceFilter() {\r\n    console.log(\"Запуск фільтрації...\"); // Перевірка в консолі F12\r\n    const roomVal = document.getElementById(\'my-rooms\').value;\r\n    const priceLimit = parseInt(document.getElementById(\'my-price\').value) || 9999999;\r\n    \r\n    // Шукаємо всі блоки оголошень\r\n    const cards = document.querySelectorAll(\'.fwre-item-listing, .fwre-item, .fwre-property-listing, .fwre-row\');\r\n    \r\n    if (cards.length === 0) {\r\n        alert(\"Скрипт не знайшов оголошень на сторінці. Перевірте класи.\");\r\n        return;\r\n    }\r\n\r\n    cards.forEach(card => {\r\n        // Витягуємо ціну (напр. \"20 000грн.\")\r\n        const priceEl = card.querySelector(\'.fwk-text-green, .fwk-h2\');\r\n        const priceText = priceEl ? priceEl.innerText.replace(/[^\\d]/g, \'\') : \"0\";\r\n        const currentPrice = parseInt(priceText);\r\n        \r\n        // Перевірка на кімнати в тексті\r\n        const cardText = card.innerText;\r\n        const roomMatch = (roomVal === \"\") || cardText.includes(roomVal);\r\n\r\n        if (currentPrice <= priceLimit && roomMatch) {\r\n            card.style.cssText = \"display: block !important; visibility: visible !important; opacity: 1 !important;\";\r\n        } else {\r\n            card.style.cssText = \"display: none !important;\";\r\n        }\r\n    });\r\n}\r\n\r\nfunction forceReset() {\r\n    document.getElementById(\'my-rooms\').value = \"\";\r\n    document.getElementById(\'my-price\').value = \"\";\r\n    document.querySelectorAll(\'.fwre-item-listing, .fwre-item, .fwre-property-listing, .fwre-row\').forEach(c => {\r\n        c.style.cssText = \"display: block !important;\";\r\n    });\r\n}\r\n</script>', 1, '', NULL, NULL, NULL, NULL, 1, 'mod_custom', 1, 1, '{\"prepare_content\":0,\"backgroundimage\":\"\",\"layout\":\"_:default\",\"moduleclass_sfx\":\"\",\"cache\":1,\"cache_time\":900,\"cachemode\":\"static\",\"module_tag\":\"div\",\"bootstrap_size\":\"0\",\"header_tag\":\"h3\",\"header_class\":\"\",\"style\":\"0\"}', 0, '*'),
