(410, 'COM_PRIVACY_ADMIN_NOTIFICATION_USER_CONFIRMED_REQUEST_SUBJECT', 'Запит інформації підтверджується користувачем', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(411, 'COM_PRIVACY_ADMIN_NOTIFICATION_USER_CREATED_REQUEST_MESSAGE', 'Створено новий інформаційний запит %1$s.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(412, 'COM_PRIVACY_ADMIN_NOTIFICATION_USER_CREATED_REQUEST_SUBJECT', 'Запит на інформацію відправленої', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(413, 'COM_PRIVACY_CONFIRM_REMIND_SUCCEEDED', 'Ваша згода на політику конфіденційності цього сайту була розширена.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(414, 'COM_PRIVACY_CONFIRM_REQUEST_FIELDSET_LABEL', 'На вашу електронну адресу надіслано повідомлення. Електронний лист має токен підтвердження. Підтвердьте свою електронну адресу ще раз й вставте токен підтвердження у поле нижче, щоб підтвердити, що ви є власником інформації, яка запитується.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(415, 'COM_PRIVACY_CONFIRM_REQUEST_SUCCEEDED', 'Ваш інформаційний запит був підтверджений. Ми обробимо ваш запит якнайшвидше, а архів з даними буде надісланий на ваш електронний лист.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(416, 'COM_PRIVACY_CREATE_REQUEST_SUCCEEDED', 'Ваш запит на інформацію створено. Перш ніж його можна буде обробити, ви повинні підтвердити цей запит. На вашу адресу надіслано електронний лист із додатковими інструкціями для завершення цієї перевірки.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(417, 'COM_PRIVACY_EMAIL_REQUEST_BODY_EXPORT_REQUEST', 'Хтось створив запит на експорт усієї особистої інформації, пов’язаної з цією електронною адресою, за адресою {URL}. Для заходів безпеки ви повинні підтвердити, що це дійсний запит на вашу особисту інформацію з цього сайту.\\n\\nЯкщо це помилка, то просто проігноруйте цей електронний лист, нічого не станеться.\\n\\nДля підтвердження цього запиту ви можете виконати одне з наступних завдань:\\n\\n1 Відвідайте таку URL-адресу: {TOKENURL}\\n2. Скопіюйте токен з цього електронного листа, відвідайте URL-адресу та вставте токен у форму.\\nURL: {FORMURL}\\nТокен: {TOKEN}\\n\\nЗверніть увагу, що цей маркер дійсний лише 24 години з моменту відправлення електронного листа.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(418, 'COM_PRIVACY_EMAIL_REQUEST_BODY_REMOVE_REQUEST', 'Хтось створив запит на видалення всієї особистої інформації, пов’язаної з цією електронною адресою, за адресою {URL}. Для заходів безпеки ви повинні підтвердити, що це дійсний запит на видалення вашої особистої інформації з цього сайту.\\n\\nЯкщо це помилка, то просто проігноруйте цей електронний лист, нічого не станеться.\\n\\nДля підтвердження цього запиту ви можете виконати одне з наступних завдань:\\n\\n1. Відвідайте таку URL-адресу: {TOKENURL}\\n\\n2. Скопіюйте токен з цього електронного листа, відвідайте URL-адресу та вставте маркер у форму.\\nURL: {FORMURL}\\nТокен: {TOKEN}\\n\\nЗверніть увагу, що цей токен дійсний лише 24 години з моменту відправлення електронний лист.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(419, 'COM_PRIVACY_EMAIL_REQUEST_SUBJECT_EXPORT_REQUEST', 'Інформаційний запит створено на сайті {SITENAME}', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(420, 'COM_PRIVACY_EMAIL_REQUEST_SUBJECT_REMOVE_REQUEST', 'Запит на видалення інформації створено на сайті {SITENAME}', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(421, 'COM_PRIVACY_ERROR_CANNOT_CREATE_REQUEST_WHEN_SENDMAIL_DISABLED', 'Інформаційний запит неможливо створити, коли підтримка електронної пошти вимкнута.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(422, 'COM_PRIVACY_ERROR_CHECKING_FOR_EXISTING_REQUESTS', 'Під час перевірки наявних інформаційних запитів сталася помилка. Спробуйте надіслати цей запит ще раз.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(423, 'COM_PRIVACY_ERROR_CONFIRM_TOKEN_EXPIRED', 'Маркер підтвердження вашого запиту на інформацію закінчився. Вам потрібно буде подати новий запит.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(424, 'COM_PRIVACY_ERROR_CONFIRMING_REMIND_FAILED', 'Нагадування про закінчення терміну дії не знайдено.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(425, 'COM_PRIVACY_ERROR_CONFIRMING_REQUEST', 'Помилка під час підтвердження запиту на інформацію.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(426, 'COM_PRIVACY_ERROR_CONFIRMING_REQUEST_FAILED', 'Помилка підтвердження вашого запиту інформації. %s', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(427, 'COM_PRIVACY_ERROR_CREATING_REQUEST', 'Помилка під час створення запиту на інформацію.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(428, 'COM_PRIVACY_ERROR_CREATING_REQUEST_FAILED', 'Ваш запит інформації не вдалося створити. %s', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(429, 'COM_PRIVACY_ERROR_NO_PENDING_REMIND', 'Нагадування про закінчення терміну дії ще не надіслане.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(430, 'COM_PRIVACY_ERROR_NO_PENDING_REQUESTS', 'На цю електронну адресу немає запитів на інформацію, які потребують підтвердження.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(431, 'COM_PRIVACY_ERROR_NO_REMIND_REQUESTS', 'Будь ласка, перевірте токен', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(432, 'COM_PRIVACY_ERROR_PENDING_REQUEST_OPEN', 'Вже є активний запит на інформацію про цю електронну адресу та тип запиту. Зверніться до власника сайту, щоб отримати оновлення щодо цього запиту.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(433, 'COM_PRIVACY_ERROR_REMIND_REQUEST', 'Сталася помилка при обробці вашого запиту.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(434, 'COM_PRIVACY_ERROR_UNKNOWN_REQUEST_TYPE', 'Невідомий тип інформаційного запиту.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(435, 'COM_PRIVACY_FIELD_CONFIRM_CONFIRM_TOKEN_DESC', 'Введіть токен підтвердження, який ви отримали електронною поштою.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(436, 'COM_PRIVACY_FIELD_CONFIRM_CONFIRM_TOKEN_LABEL', 'Токен підтвердження', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(437, 'COM_PRIVACY_FIELD_CONFIRM_EMAIL_DESC', 'Введіть свою адресу електронної пошти.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(438, 'COM_PRIVACY_FIELD_REMIND_CONFIRM_TOKEN_DESC', 'Введіть токен підтвердження, який ви отримали електронною поштою.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
