(447, 'COM_PRIVACY_VIEW_REQUEST_PAGE_TITLE', 'Надіслати інформаційний запит', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
(448, 'COM_PRIVACY_WARNING_CANNOT_CREATE_REQUEST_WHEN_SENDMAIL_DISABLED', 'На жаль, наразі ви не можете подати запит на інформацію.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_privacy.ini'),
