(457, 'COM_USERS_ACTIVATION_TOKEN_NOT_FOUND', 'Код підтвердження не знайдено.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(458, 'COM_USERS_CAPTCHA_LABEL', 'CAPTCHA', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(459, 'COM_USERS_DATABASE_ERROR', 'Помилка вибірки користувача з бази даних: %s', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(460, 'COM_USERS_EDIT_PROFILE', 'Редагувати обліковий запис', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(461, 'COM_USERS_EMAIL_ACCOUNT_DETAILS', 'Деталі облікового запису для {NAME} у {SITENAME}', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(462, 'COM_USERS_EMAIL_ACTIVATED_BY_ADMIN_ACTIVATION_BODY', 'Вітаємо вас, шановний %s!\\n\\nВаш обліковий запис активовано адміністрацією сайту. Відтепер ви можете використовувати свій логін %s та пароль, який ви ввели під час реєстрації на сайті.\\n\\nДякуємо!', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(463, 'COM_USERS_EMAIL_ACTIVATED_BY_ADMIN_ACTIVATION_SUBJECT', 'Обліковий запис активовано для {NAME} на {SITENAME}', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(464, 'COM_USERS_EMAIL_ACTIVATE_WITH_ADMIN_ACTIVATION_BODY', 'Вітаємо вас, шановний Адміністратор!\\n\\nНовий користувач зареєструвався на {SITENAME}.\\nКористувач перевірив свою електронну скриньку і просить вас, щоб ви схвалили його обліковий запис.\\nЦей лист містить наступні дані про нового користувача:\\n\\nІм\'я: {NAME}\\nАдреса електронної пошти: {EMAIL}\\nЛогін: {USERNAME}\\n\\nЩоб активувати користувача перейдіть за наступним посиланням:\\n{ACTIVATE}', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(465, 'COM_USERS_EMAIL_ACTIVATE_WITH_ADMIN_ACTIVATION_SUBJECT', 'Необхідно дозвіл для реєстрації {NAME} на {SITENAME}', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(466, 'COM_USERS_EMAIL_PASSWORD_RESET_BODY', 'Вітаємо!\\n\\nВи або хтось інший зробили запит на зміну пароля до вашого облікового запису {SITENAME}.\\n\\nЯкщо запит був створений вами, будь ласка, перейдіть по посиланню, наведеному нижче, щоб підтвердити код на зміну паролю та приступити до процедури зміни вашого паролю на новий.\\n\\n{LINK_TEXT}\\n\\nДякуємо!', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(467, 'COM_USERS_EMAIL_PASSWORD_RESET_SUBJECT', 'Ваш {SITENAME} запит на зміну паролю', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(468, 'COM_USERS_EMAIL_REGISTERED_BODY', 'Доброго дня, {NAME},\\n\\nДякуємо за реєстрацію на {SITENAME}.\\n\\nТепер ви можете увійти на {SITEURL}, використовуючи наступні ім\'я користувача та пароль:\\n\\nІм\'я користувача: {USERNAME}\\nПароль: {PASSWORD_CLEAR}', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(469, 'COM_USERS_EMAIL_REGISTERED_BODY_NOPW', 'Привіт {NAME},\\n\\nДякуємо за реєстрацію на {SITENAME}.\\n\\nТепер ви можете увійти на {SITEURL}, використовуючи ім\'я користувача та пароль, з якими ви зареєструвалися.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(470, 'COM_USERS_EMAIL_REGISTERED_NOTIFICATION_TO_ADMIN_BODY', 'Привіт адміністратор, \\n\\nНовий користувач \"{NAME}\", ім\'я користувача \"{USERNAME}\", зареєструвався на {SITEURL}.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(471, 'COM_USERS_EMAIL_REGISTERED_WITH_ACTIVATION_BODY', 'Доброго дня {NAME},\\n\\nДякуємо за реєстрацію на {SITENAME}. Ваш обліковий запис створений і повинен бути активований, перш ніж ви зможете ним користуватися.\\nДля активації облікового запису перейдіть за наступним посиланням або скопіюйте його у вашому браузері:\\n{ACTIVATE}. \\n\\nПісля активації ви можете увійти на {SITEURL}, використовуючи наступні ім\'я користувача та пароль:\\n\\nІм\'я користувача: {USERNAME}\\nПароль: {PASSWORD_CLEAR}.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(472, 'COM_USERS_EMAIL_REGISTERED_WITH_ACTIVATION_BODY_NOPW', 'Доброго дня {NAME},\\n\\nДякуємо за реєстрацію на {SITENAME}. Ваш обліковий запис створений і повинен бути активований, перш ніж ви зможете ним користуватися.\\nДля активації облікового запису перейдіть за наступним посиланням або скопіюйте його у вашому браузері:\\n{ACTIVATE}. \\n\\nПісля активації ви можете зайти на {SITEURL}, використовуючи наступне ім\'я користувача і пароль, які ви ввели при реєстрації:\\n\\nІм\'я користувача: {USERNAME}.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(473, 'COM_USERS_EMAIL_REGISTERED_WITH_ADMIN_ACTIVATION_BODY', 'Доброго дня {NAME},\\n\\nДякуємо за реєстрацію на {SITENAME}. Ваш обліковий запис створений і повинен бути підтверджений, перш ніж ви зможете ним користуватися.\\n\\nДля підтвердження облікового запису перейдіть за наступним посиланням або скопіюйте його у вашому браузері:\\n{ACTIVATE}. \\n\\nПісля верифікації буде надіслано повідомлення адміністратору для активації вашого облікового запису. Ви отримаєте підтвердження, коли це буде зроблено.\\n\\nПісля активації облікового запису ви можете увійти на {SITEURL}, використовуючи наступні ім\'я користувача та пароль:\\n\\nІм\'я користувача: {USERNAME}\\nПароль: {PASSWORD_CLEAR}.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(474, 'COM_USERS_EMAIL_REGISTERED_WITH_ADMIN_ACTIVATION_BODY_NOPW', 'Доброго дня {NAME},\\n\\nДякуємо за реєстрацію на {SITENAME}. Ваш обліковий запис створений і повинен бути підтверджений, перш ніж ви зможете ним користуватися.\\n\\nДля підтвердження облікового запису перейдіть за наступним посиланням або скопіюйте його у вашому браузері:\\n{ACTIVATE}. \\n\\nПісля верифікації буде надіслано повідомлення адміністратору для активації вашого облікового запису. Ви отримаєте підтвердження, коли це буде зроблено.\\n\\nПісля активації облікового запису ви можете увійти на {SITEURL}, використовуючи наступне ім\'я користувача та пароль, які ви ввели при реєстрації:\\n\\nІм\'я користувача: {USERNAME}.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(475, 'COM_USERS_EMAIL_USERNAME_REMINDER_BODY', 'Доброго дня,\\n\\nДля вашого облікового запису {SITENAME} було надіслано нагадування про ім\'я користувача.\\n\\nВаше ім\'я користувача — {USERNAME}.\\n\\nЩоб увійти до свого облікового запису, перейдіть за посиланням нижче.\\n\\n{LINK_TEXT} \\n\\nДякую.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
