(498, 'COM_USERS_MFA_BACKUPCODES_PRINT_PROMPT', 'Резервні коди дозволяють увійти на сайт, якщо ваш звичайний метод багатофакторної автентифікації не працює або ви більше не маєте до нього доступу. Кожен код може бути використаний <em>тільки один раз</em>.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(499, 'COM_USERS_MFA_BACKUPCODES_PRINT_PROMPT_HEAD', '<a href=\"%1$s\" class=\"%2$s\">Роздрукуйте коди</a> та зберігайте їх у своєму гаманці.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(500, 'COM_USERS_MFA_BACKUPCODES_RESET', 'Відновлення резервних кодів', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(501, 'COM_USERS_MFA_BACKUPCODES_RESET_INFO', 'Скористайтеся кнопкою нижче, щоб згенерувати новий набір резервних кодів. Ми рекомендуємо вам зробити це, якщо ви вважаєте, що ваші Резервні коди скомпрометовані, наприклад, хтось отримав роздруківку з ними, або якщо у вас закінчується кількість доступних Резервних кодів.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(502, 'COM_USERS_MFA_EDIT_FIELD_DEFAULT', 'Зробити метод багатофакторної автентифікації за налаштуванням', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(503, 'COM_USERS_MFA_EDIT_FIELD_TITLE', 'Назва', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(504, 'COM_USERS_MFA_EDIT_FIELD_TITLE_DESC', 'Ви та адміністратори сайту побачите це ім\'я в списку доступних методів багатофакторної автентифікації для вашого облікового запису. Будь ласка, не вказуйте ніякої конфіденційної або персональної інформації.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(505, 'COM_USERS_MFA_EDIT_PAGE_HEAD', 'Зміна методу багатофакторної автентифікації', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(506, 'COM_USERS_MFA_FIRSTTIME_INSTRUCTIONS_HEAD', 'Використовуйте багатофакторну автентифікацію для додаткової безпеки', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(507, 'COM_USERS_MFA_FIRSTTIME_INSTRUCTIONS_WHATITDOES', 'Ось як це працює. Нижче додайте метод багатофакторної автентифікації. Відтепер кожного разу, коли ви входите на сайт, вам буде запропоновано використати цей метод для завершення входу. Навіть якщо хтось вкраде ваше ім’я користувача та пароль, вони не матимуть доступу до вашого облікового запису на цьому сайті.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
