(558, 'COM_USERS_REGISTRATION_ACL_ADMIN_ACTIVATION', 'Будь ласка, увійдіть, щоб підтвердити право активації нових облікових записів.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(559, 'COM_USERS_REGISTRATION_ACL_ADMIN_ACTIVATION_PERMISSIONS', 'Ви не маєте прав для активації нових облікових записів, будь ласка, увійдіть у систему з привілейованого облікового запису.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(560, 'COM_USERS_REGISTRATION_ACTIVATE_SUCCESS', 'Ваш обліковий запис був успішно активований. ви можете тепер увійти на сайт, використовуючи логін і пароль, зазначені вами при реєстрації.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(561, 'COM_USERS_REGISTRATION_ACTIVATION_NOTIFY_SEND_MAIL_FAILED', 'Помилка під час відправлення листа електронної пошти з повідомленням про активацію', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(562, 'COM_USERS_REGISTRATION_ACTIVATION_SAVE_FAILED', 'Не вдалося зберегти дані активації: %s', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(563, 'COM_USERS_REGISTRATION_ADMINACTIVATE_SUCCESS', 'Обліковий запис користувача було успішно активовано, і користувач був повідомлений про це.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(564, 'COM_USERS_REGISTRATION_COMPLETE_ACTIVATE', 'Реєстрація завершена! ваш обліковий запис створено і на зазначену вами електронну адресу надіслано інструкцію з активації. Нічого складного — у листі посилання, за яким вам необхідно перейти.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(565, 'COM_USERS_REGISTRATION_COMPLETE_VERIFY', 'Ваш обліковий запис створено і на вашу адресу електронної пошти надіслано листа для підтвердження. Зверніть увагу, що необхідно верифікувати обліковий запис, перейшовши по посиланню верифікації, коли ви отримаєте листа, а потім Адміністрація сайту активує ваш обліковий запис, перш ніж ви зможете Увійти.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(566, 'COM_USERS_REGISTRATION_DEFAULT_LABEL', 'Реєстрація користувача', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(567, 'COM_USERS_REGISTRATION_SAVE_FAILED', 'Помилка реєстрації: %s', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(568, 'COM_USERS_REGISTRATION_SAVE_SUCCESS', 'Дякуємо вам за реєстрацію. Тепер ви можете увійти, використовуючи логін і пароль, введені під час реєстрації.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(569, 'COM_USERS_REGISTRATION_SEND_MAIL_FAILED', 'Сталася помилка при відправленні листа реєстрації електронною поштою. Повідомлення було відправлено Адміністрації сайту.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(570, 'COM_USERS_REGISTRATION_VERIFY_SUCCESS', 'Ваше повідомлення було верифіковано. Як тільки Адміністрація схвалить ваш обліковий запис, ви зможете Увійти на сайт. Повідомлення про схвалення ви отримаєте на свою поштову скриньку.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(571, 'COM_USERS_REMIND', 'Нагадування', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(572, 'COM_USERS_REMIND_DEFAULT_LABEL', 'Будь ласка, введіть адресу електронної пошти, на яку ви створювали свій обліковий запис. ваш логін буде надісланий на цю електронну адресу.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(573, 'COM_USERS_REMIND_LIMIT_ERROR_N_HOURS', 'Ви перевищили максимальну кількість скидань паролю. Будь ласка, спробуйте ще раз через %s годин.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(574, 'COM_USERS_REMIND_LIMIT_ERROR_N_HOURS_1', 'Ви перевищили максимальну кількість скидань паролю. Будь ласка, спробуйте ще раз через %s годину.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(575, 'COM_USERS_REMIND_REQUEST', 'Якщо введена вами адреса електронної пошти зареєстрована на цьому сайті, то найближчим часом Ви отримаєте лист з нагадуванням.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(576, 'COM_USERS_REMIND_REQUEST_ERROR', 'Помилка при запиті нагадування пароля.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(577, 'COM_USERS_REMIND_REQUEST_FAILED', 'Нагадування, помилка: %s', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(578, 'COM_USERS_REMIND_REQUEST_SUCCESS', 'Нагадування успішно відправлено на вашу адресу електронної пошти.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(579, 'COM_USERS_REMIND_SUPERADMIN_ERROR', 'Super User не може створити запит нагадування пароля. Будь ласка, зв\'яжіться з іншим Super User або використовуйте альтернативний метод.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(580, 'COM_USERS_RESET', 'Пароль скинуто', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(581, 'COM_USERS_RESET_COMPLETE_ERROR', 'Помилка завершення скидання пароля.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(582, 'COM_USERS_RESET_COMPLETE_FAILED', 'Завершення скидання пароля не вдалося: %s', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(583, 'COM_USERS_RESET_COMPLETE_LABEL', 'Для завершення процесу зміни пароля, будь ласка, введіть новий пароль.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(584, 'COM_USERS_RESET_COMPLETE_SUCCESS', 'Скидання пароля успішне. Тепер ви можете увійти на сайт.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(585, 'COM_USERS_RESET_COMPLETE_TOKENS_MISSING', 'Не вдалося підтвердити скидання вашого пароля, оскільки код верифікації відсутній.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(586, 'COM_USERS_RESET_CONFIRM_ERROR', 'Помилка при підтверджуванні паролю', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(587, 'COM_USERS_RESET_CONFIRM_FAILED', 'Не вдалося підтвердити скидання вашого пароля, оскільки код верифікації визнано недійсним. %s', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(588, 'COM_USERS_RESET_CONFIRM_LABEL', 'Лист надіслано на вашу адресу електронної пошти. У листі міститься код верифікації. Вставте цей код в поле, наведене нижче, щоб підтвердити, що ви є власником цього облікового запису.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(589, 'COM_USERS_RESET_REQUEST', 'Якщо введена вами адреса електронної пошти зареєстрована на цьому сайті, то найближчим часом Ви отримаєте лист із посиланням для відновлення паролю до вашого облікового запису.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(590, 'COM_USERS_RESET_REQUEST_ERROR', 'Помилка при запиті відновлення пароля.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(591, 'COM_USERS_RESET_REQUEST_FAILED', 'Помилка відновлення пароля: %s', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(592, 'COM_USERS_RESET_REQUEST_LABEL', 'Будь ласка, введіть адресу електронної пошти для вашого облікового запису. Код верифікації буде надісланий на цю адресу. Після того як ви отримаєте код верифікації, ви зможете обрати новий пароль для вашого облікового запису.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(593, 'COM_USERS_SETTINGS_FIELDSET_LABEL', 'Базові налаштування', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(594, 'COM_USERS_USER_ALLOWTOURAUTOSTART_LABEL', 'Дозволити автоматичний запуск турів', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(595, 'COM_USERS_USER_BACKUPCODE', 'Резервний код', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(596, 'COM_USERS_USER_BACKUPCODES', 'Резервні коди', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(597, 'COM_USERS_USER_BACKUPCODES_CAPTIVE_PROMPT', 'Якщо ви не маєте доступу до вашого звичайного методу багатофакторної автентифікації, використовуйте будь-який з ваших резервних кодів у полі нижче. Будь ласка, пам\'ятайте, що цей аварійний резервний код не може бути використаний повторно.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(598, 'COM_USERS_USER_BACKUPCODES_DESC', 'Якщо ви не маєте доступу до пристрою багатофакторної автентифікації, ви можете використовувати будь-який з наведених нижче паролів замість звичайного коду безпеки. Кожен з цих аварійних кодів негайно знищується після використання. Ми рекомендуємо роздрукувати ці коди та зберігати роздруківку в безпечному та доступному місці, наприклад, у гаманці або банківському сейфі.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(599, 'COM_USERS_USER_BLOCKED', 'Цей користувач заблокований. Якщо це помилка, то, будь ласка, зв\'яжіться з адміністрацією сайту.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
(600, 'COM_USERS_USER_COLORSCHEME_LABEL', 'Тема шаблону', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\com_users.ini'),
