INSERT INTO `duew9_overrider` (`id`, `constant`, `string`, `file`) VALUES
(2092, 'JLIB_RULES_SAVE_BEFORE_CHANGE_PERMISSIONS', 'Будь ласка, збережіть, перш ніж змінювати дозволи.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\lib_joomla.ini'),
(2093, 'JLIB_RULES_SELECT_SETTING', 'Нове значення', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\lib_joomla.ini'),
(2094, 'JLIB_RULES_SETTING_NOTES', 'Якщо ви зміните налаштування, то вони будуть застосовані до цієї та всіх дочірніх груп, компонентів і вмісту. Зверніть увагу, що <em>Заборонено</em> — означає, що буде перекривати будь-які успадковані налаштування, а також налаштування в будь-якій дочірній групі, компоненті або вмісті. У випадку конфлікту налаштувань, <em>Заборонено</em> — означає, що буде мати перевагу. <em>Не встановлено</em> відповідає <em>Заборонено</em>, але може бути змінене в дочірніх групах, компонентах або вмісті.<br>Якщо ви обрали нове налаштування, то натисніть <em>Зберегти</em> для оновлення налаштувань.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\lib_joomla.ini'),
(2095, 'JLIB_RULES_SETTING_NOTES_ITEM', 'Якщо ви зміните налаштування, то вони будуть застосовані до цього елемента. Зверніть увагу, що:<br><em><strong>Успадкований</strong></em> — означає, що будуть використовуватися дозволи від загальної конфігурації, батьківської групи та категорії<br><em><strong>Відмовлено</strong></em> — означає, що незалежно від налаштувань загальної конфігурації, батьківської групи або категорії, редагована група не може виконувати цю дію щодо цього елемента.<br><em><strong>Дозволено</strong></em> — означає, що редагована група зможе виконати цю дію щодо цього елемента (але якщо це суперечить загальній конфігурації, батьківській групі чи категорії, це не вплине; конфлікт буде позначено <em><strong> Не дозволено (успадковано)</strong></em> у розділі \"Розрахункові налаштування\").', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\lib_joomla.ini'),
(2096, 'JLIB_RULES_SETTINGS_DESC', 'Налаштування дозволів для цієї групи користувачів.', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\lib_joomla.ini'),
