(2564, 'MOD_RELATED_FIELD_MAX_DESC', 'Максимальна кількість статей для показу (за налаштуванням — 5)', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\mod_related_items.ini'),
(2565, 'MOD_RELATED_FIELD_MAX_LABEL', 'Максимум статей', 'C:\\xampp\\htdocs\\veteran\\language\\uk-UA\\mod_related_items.ini'),
