(2999, 'NR_ASSIGN_REFERRER_DESC2', 'Націлити відвідувачів, які приземляються на ваш сайт із певного джерела трафіку', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini');
