(3000, 'NR_ASSIGN_REFERRER_DESC', 'Введіть одну URL-адресу переліку на рядок: Наприклад: <br> <br> google.com <Br> facebook.com/mypage', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3001, 'NR_ASSIGN_REFERRER_NOTE', 'Майте на увазі, що виявлення URL-адреса не завжди є 100% точним. Деякі сервери можуть використовувати проксі-сервери, які знімають цю інформацію, і її можна легко підробляти.\"_QQ_\"NR_PROFEATURE_HEADER=\"_QQ_\"<em>%s</em> is a PRO Feature', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3002, 'NR_PROFEATURE_HEADER', '<em>%s</em>це PRO функція', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3003, 'NR_PROFEATURE_DESC', 'Вибачте, це <em>%s</em> недоступно в вашій версії. Будь ласка змініть вашу підписку на ПРО щоби розблокувати ці дивовижні функції', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3004, 'NR_PROFEATURE_DISCOUNT', '<b>Бонус</b>: %s користувачы отримують <b>20&#37;</b> знижки автоматично при оплаті.', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3005, 'NR_ONLY_AVAILABLE_IN_PRO', 'Доступно тільки у версії PRO', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3006, 'NR_UPGRADE_TO_PRO', 'Оновити до PRO', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3007, 'NR_UPGRADE_TO_PRO_TO_UNLOCK', 'Оновитися до версії Pro', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3008, 'NR_UPGRADE_TO_PRO_VERSION', 'Дивовижно! Залишився лише один крок Натисніть кнопку нижче, щоб завершити оновлення до версії Pro.', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3009, 'NR_UNLOCK_PRO_FEATURE', 'Розблокувати функції ПРО', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3010, 'NR_USING_THE_FREE_VERSION', 'Ви використовуєте БЕЗКОШТОВУ версію Convert Forms. Придбайте PRO версію для повного функціоналу ', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
