(3013, 'NR_BGIMAGE', 'Зображення фону', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3014, 'NR_BGIMAGE_DESC', 'Встановити зображення фону', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3015, 'NR_BGIMAGE_FILE', 'Зображення', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3016, 'NR_BGIMAGE_FILE_DESC', 'Виберіть або завантажте файл, в якості фону.', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3017, 'NR_BGIMAGE_REPEAT', 'Повтор', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3018, 'NR_BGIMAGE_REPEAT_DESC', 'Повтор фону встановлює, режим, в якому фотов зображення буде повторюватися. За замовчуванням, фонове зображення повторюється як по вертикалі, так і по горизонталі. <Br> <Br> Повтор: Фонове зображення повторюється як по вертикалі, так і по горизонталі . <br> <br> Повтор-x: Фонове зображення повторюється по горизонталі <Br> <br> Повтор-y: Фонове зображення повторюється по вертикалі <br> <br> Ні-повтору: Повтор зображення відключений. ', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3019, 'NR_BGIMAGE_SIZE', 'Розмір', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3020, 'NR_BGIMAGE_SIZE_DESC', 'Вкажіть розмір фонового зображення. <br> <br> Авто: Фонове зображення містить власні ширину і висоту <br> <br> Обкладинка: Масштабує фонове зображення на максимальний розмір, щоб покрити фонове простір <br> <br> Контейнер: масштабує зображення таким чином, що його ширина і висота його може поміститися усередині області вмісту <br> <br> 100% 100%: Розтягує фонове зображення, щоб повністю покрити область контенту. ', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3021, 'NR_BGIMAGE_POSITION', 'Позиція', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3022, 'NR_BGIMAGE_POSITION_DESC', 'Властивість background-position задає початкове положення зображення. За умолачнію розміщується зверху-ліворуч. Перше значення для горизонтального позиціонування, друге для вертикального <br> <br> Ви можете використовувати одне із зумовлених значень, або введіть значення у відсотках: x% y% або в пікселях xPos yPos. ', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
(3023, 'NR_RTL', 'Включити RTL', 'C:\\xampp\\htdocs\\veteran\\plugins\\system\\nrframework\\language\\uk-UA\\uk-UA.plg_system_nrframework.ini'),
