9\\u043e \\u0434\\u043e\\u0437\\u0432\\u043e\\u043b\\u044f\\u0454 \\u043d\\u0435\\u0437\\u0440\\u044f\\u0447\\u0438\\u043c \\u0456 \\u0441\\u043b\\u0430\\u0431\\u043e\\u0437\\u043e\\u0440\\u0438\\u043c \\u043a\\u043e\\u0440\\u0438\\u0441\\u0442\\u0443\\u0432\\u0430\\u0447\\u0430\\u043c \\u0432\\u0437\\u0430\\u0454\\u043c\\u043e\\u0434\\u0456\\u044f\\u0442\\u0438 \\u0437 \\u0444\\u0456\\u0437\\u0438\\u0447\\u043d\\u0438\\u043c\\u0438 \\u043e\\u0431\\u2019\\u0454\\u043a\\u0442\\u0430\\u043c\\u0438, \\u043a\\u0430\\u0440\\u0442\\u0430\\u043c\\u0438 \\u0442\\u0430 3D-\\u043c\\u043e\\u0434\\u0435\\u043b\\u044f\\u043c\\u0438. \\u0414\\u043e\\u0442\\u0438\\u043a \\u0434\\u043e \\u043f\\u043e\\u0442\\u0440\\u0456\\u0431\\u043d\\u043e\\u0457 \\u0442\\u043e\\u0447\\u043a\\u0438 \\u0437\\u0430\\u043f\\u0443\\u0441\\u043a\\u0430\\u0454 \\u0430\\u0443\\u0434\\u0456\\u043e\\u043e\\u043f\\u0438\\u0441 \\u043f\\u0440\\u043e\\u0441\\u0442\\u043e\\u0440\\u0443.<\\/p><p style=\\\"text-align:justify;\\\">\\u0423 \\u0420\\u0456\\u0432\\u043d\\u0435\\u043d\\u0441\\u044c\\u043a\\u043e\\u043c\\u0443 \\u0444\\u0430\\u0445\\u043e\\u0432\\u043e\\u043c\\u0443 \\u043a\\u043e\\u043b\\u0435\\u0434\\u0436\\u0456 \\u0456\\u043d\\u0444\\u043e\\u0440\\u043c\\u0430\\u0446\\u0456\\u0439\\u043d\\u0438\\u0445 \\u0442\\u0435\\u0445\\u043d\\u043e\\u043b\\u043e\\u0433\\u0456\\u0439 CamIO \\u0434\\u043e\\u043f\\u043e\\u043c\\u0430\\u0433\\u0430\\u0454 \\u0441\\u0442\\u0443\\u0434\\u0435\\u043d\\u0442\\u0430\\u043c \\u0437 \\u043f\\u043e\\u0440\\u0443\\u0448\\u0435\\u043d\\u043d\\u044f\\u043c\\u0438 \\u0437\\u043e\\u0440\\u0443 \\u0437\\u043d\\u0430\\u0445\\u043e\\u0434\\u0438\\u0442\\u0438 \\u0430\\u0443\\u0434\\u0438\\u0442\\u043e\\u0440\\u0456\\u0457, \\u043b\\u0430\\u0431\\u043e\\u0440\\u0430\\u0442\\u043e\\u0440\\u0456\\u0457 \\u0439 \\u0433\\u0440\\u043e\\u043c\\u0430\\u0434\\u0441\\u044c\\u043a\\u0456 \\u0437\\u043e\\u043d\\u0438 \\u0437\\u0430 \\u0434\\u043e\\u043f\\u043e\\u043c\\u043e\\u0433\\u043e\\